const __dirname = path.dirname(fileURLToPath(import.meta.url));
const root = path.join(__dirname, '..');

const files = {"src/types/index.ts":"export const PILOT_NUMBER_MIN = 4;\nexport const PILOT_NUMBER_MAX = 999;\n\nexport interface Category {\n  id: string;\n  label: string;\n  minAge: number;\n  maxAge: number;\n}\n\nexport const CATEGORIES: Category[] = [\n  { id: '50cc-a', label: '50cc A', minAge: 4, maxAge: 6 },\n  { id: '50cc-b', label: '50cc B', minAge: 6, maxAge: 8 },\n  { id: '65cc-a', label: '65cc A', minAge: 7, maxAge: 9 },\n  { id: '65cc-b', label: '65cc B', minAge: 8, maxAge: 10 },\n  { id: '85cc-a', label: '85cc A', minAge: 9, maxAge: 11 },\n  { id: '85cc-b', label: '85cc B', minAge: 11, maxAge: 13 },\n  { id: '125cc-junior', label: '125cc Junior', minAge: 12, maxAge: 17 },\n];\n\nexport function getCategoryById(id: string): Category | undefined {\n  return CATEGORIES.find((c) => c.id === id);\n}\n\nexport function getCategoriesForAge(age: number): Category[] {\n  if (age < 0) return [];\n  return CATEGORIES.filter((c) => age >= c.minAge && age <= c.maxAge);\n}\n\nexport interface Event {\n  id: string;\n  name: string;\n  date: string;\n  location: string;\n  city: string;\n  description: string;\n  active: boolean;\n}\n\nexport interface Registration {\n  id: string;\n  eventId: string;\n  nombre: string;\n  apellido: string;\n  identificacion: string;\n  identificacionArchivo: string;\n  identificacionFileName: string;\n  identificacionFileType: string;\n  comprobantePagoArchivo: string;\n  comprobantePagoFileName: string;\n  comprobantePagoFileType: string;\n  fechaNacimiento: string;\n  edad: number;\n  email: string;\n  celular: string;\n  ciudad: string;\n  marcaMoto: string;\n  numeroPiloto: number;\n  categoriaId: string;\n  categoriaLabel: string;\n  createdAt: string;\n  updatedAt: string;\n}\n\nexport interface RegistrationFormData {\n  eventId: string;\n  nombre: string;\n  apellido: string;\n  identificacion: string;\n  identificacionArchivo: string;\n  identificacionFileName: string;\n  identificacionFileType: string;\n  comprobantePagoArchivo: string;\n  comprobantePagoFileName: string;\n  comprobantePagoFileType: string;\n  fechaNacimiento: string;\n  email: string;\n  celular: string;\n  ciudad: string;\n  marcaMoto: string;\n  numeroPiloto: number;\n  categoriaIds: string[];\n}\n\nexport interface AppData {\n  events: Event[];\n  registrations: Registration[];\n}","src/utils/storage.ts":"import { CONFIG } from '../config';\nimport type { AppData, Event, Registration, RegistrationFormData } from '../types';\nimport { calculateAge, generateId, parseSheetDate } from './age';\nimport { getCategoryById } from '../types';\nimport {\n  apiGet,\n  apiPost,\n  checkPilotNumberRemote,\n  getAvailablePilotNumbers as fetchAvailablePilotNumbers,\n  isApiEnabled,\n  allPilotNumbers,\n} from './api';\n\nasync function fetchJson<T>(url: string): Promise<T | null> {\n  try {\n    const res = await fetch(url);\n    if (!res.ok) return null;\n    return (await res.json()) as T;\n  } catch {\n    return null;\n  }\n}\n\nfunction readLocal<T>(key: string): T | null {\n  try {\n    const raw = localStorage.getItem(key);\n    return raw ? (JSON.parse(raw) as T) : null;\n  } catch {\n    return null;\n  }\n}\n\nfunction writeLocal<T>(key: string, data: T): void {\n  localStorage.setItem(key, JSON.stringify(data));\n}\n\nfunction normalizeEvent(raw: Record<string, unknown>): Event {\n  const active = raw.active;\n  return {\n    id: String(raw.id ?? ''),\n    name: String(raw.name ?? ''),\n    date: parseSheetDate(raw.date),\n    location: String(raw.location ?? ''),\n    city: String(raw.city ?? ''),\n    description: String(raw.description ?? ''),\n    active: active === true || active === 'TRUE' || active === 'true' || active === 1,\n  };\n}\n\nfunction normalizeRegistration(raw: Record<string, unknown>): Registration {\n  return {\n    id: String(raw.id ?? ''),\n    eventId: String(raw.eventId ?? ''),\n    nombre: String(raw.nombre ?? ''),\n    apellido: String(raw.apellido ?? ''),\n    identificacion: String(raw.identificacion ?? ''),\n    identificacionArchivo: String(raw.identificacionArchivo ?? raw.identificacionDriveUrl ?? ''),\n    identificacionFileName: String(raw.identificacionFileName ?? ''),\n    identificacionFileType: String(raw.identificacionFileType ?? ''),\n    comprobantePagoArchivo: String(raw.comprobantePagoArchivo ?? ''),\n    comprobantePagoFileName: String(raw.comprobantePagoFileName ?? ''),\n    comprobantePagoFileType: String(raw.comprobantePagoFileType ?? ''),\n    fechaNacimiento: String(raw.fechaNacimiento ?? ''),\n    edad: Number(raw.edad ?? 0),\n    email: String(raw.email ?? ''),\n    celular: String(raw.celular ?? ''),\n    ciudad: String(raw.ciudad ?? ''),\n    marcaMoto: String(raw.marcaMoto ?? ''),\n    numeroPiloto: Number(raw.numeroPiloto ?? 0),\n    categoriaId: String(raw.categoriaId ?? ''),\n    categoriaLabel: String(raw.categoriaLabel ?? ''),\n    createdAt: String(raw.createdAt ?? ''),\n    updatedAt: String(raw.updatedAt ?? ''),\n  };\n}\n\nexport async function loadEvents(): Promise<Event[]> {\n  if (isApiEnabled()) {\n    try {\n      const data = await apiGet<{ events: Record<string, unknown>[] }>({ action: 'events' });\n      return (data.events ?? []).map(normalizeEvent);\n    } catch {\n      /* fallback below */\n    }\n  }\n\n  const fromLocal = readLocal<Event[]>(CONFIG.storageKeys.events);\n  if (fromLocal?.length) return fromLocal.map((e) => normalizeEvent(e as unknown as Record<string, unknown>));\n\n  const fromFile = await fetchJson<Event[]>('./data/events.json');\n  return (fromFile ?? []).map((e) => normalizeEvent(e as unknown as Record<string, unknown>));\n}\n\nexport async function saveEvents(events: Event[]): Promise<void> {\n  if (isApiEnabled()) {\n    await apiPost({ action: 'saveEvents', events });\n    return;\n  }\n  writeLocal(CONFIG.storageKeys.events, events);\n}\n\nexport async function loadRegistrations(): Promise<Registration[]> {\n  if (isApiEnabled()) {\n    try {\n      const data = await apiGet<{ registrations: Record<string, unknown>[] }>({\n        action: 'registrations',\n      });\n      return (data.registrations ?? []).map(normalizeRegistration);\n    } catch {\n      /* fallback below */\n    }\n  }\n\n  const fromLocal = readLocal<Registration[]>(CONFIG.storageKeys.registrations);\n  const fromFile = await fetchJson<Registration[]>('./data/registrations.json');\n\n  const merged = new Map<string, Registration>();\n  for (const reg of fromFile ?? []) merged.set(reg.id, normalizeRegistration(reg as unknown as Record<string, unknown>));\n  for (const reg of fromLocal ?? []) merged.set(reg.id, normalizeRegistration(reg as unknown as Record<string, unknown>));\n\n  return Array.from(merged.values());\n}\n\nexport async function saveRegistrations(registrations: Registration[]): Promise<void> {\n  if (isApiEnabled()) {\n    await apiPost({ action: 'saveRegistrations', registrations });\n    return;\n  }\n  writeLocal(CONFIG.storageKeys.registrations, registrations);\n}\n\nexport function getTakenPilotNumbers(\n  registrations: Registration[],\n  eventId: string,\n  excludeId?: string\n): Set<number> {\n  return new Set(\n    registrations\n      .filter((r) => r.eventId === eventId && r.id !== excludeId)\n      .map((r) => r.numeroPiloto)\n  );\n}\n\nexport function isPilotNumberAvailable(\n  registrations: Registration[],\n  eventId: string,\n  number: number,\n  excludeId?: string\n): boolean {\n  return !getTakenPilotNumbers(registrations, eventId, excludeId).has(number);\n}\n\nexport async function isPilotNumberAvailableAsync(\n  eventId: string,\n  number: number,\n  excludeId?: string\n): Promise<boolean> {\n  if (isApiEnabled()) {\n    return checkPilotNumberRemote(eventId, number, excludeId);\n  }\n  const registrations = await loadRegistrations();\n  return isPilotNumberAvailable(registrations, eventId, number, excludeId);\n}\n\nexport async function getAvailablePilotNumbers(eventId: string): Promise<number[]> {\n  if (isApiEnabled()) {\n    const numbers = await fetchAvailablePilotNumbers(eventId);\n    if (numbers.length) return numbers;\n  }\n  const registrations = await loadRegistrations();\n  const taken = getTakenPilotNumbers(registrations, eventId);\n  return allPilotNumbers().filter((n) => !taken.has(n));\n}\n\nfunction resolveCategoryFields(categoriaIds: string[]): { categoriaId: string; categoriaLabel: string } {\n  const labels = categoriaIds.map((id) => getCategoryById(id)?.label ?? id);\n  return {\n    categoriaId: categoriaIds.join(','),\n    categoriaLabel: labels.join('|'),\n  };\n}\n\nexport async function createRegistration(data: RegistrationFormData): Promise<Registration> {\n  const { categoriaId, categoriaLabel } = resolveCategoryFields(data.categoriaIds);\n  const edad = calculateAge(data.fechaNacimiento);\n  const now = new Date().toISOString();\n\n  const registration: Registration = {\n    id: generateId(),\n    eventId: data.eventId,\n    nombre: data.nombre.trim(),\n    apellido: data.apellido.trim(),\n    identificacion: data.identificacion.trim(),\n    identificacionArchivo: data.identificacionArchivo,\n    identificacionFileName: data.identificacionFileName,\n    identificacionFileType: data.identificacionFileType,\n    comprobantePagoArchivo: data.comprobantePagoArchivo,\n    comprobantePagoFileName: data.comprobantePagoFileName,\n    comprobantePagoFileType: data.comprobantePagoFileType,\n    fechaNacimiento: data.fechaNacimiento,\n    edad,\n    email: data.email.trim(),\n    celular: data.celular.trim(),\n    ciudad: data.ciudad.trim(),\n    marcaMoto: data.marcaMoto.trim(),\n    numeroPiloto: data.numeroPiloto,\n    categoriaId,\n    categoriaLabel,\n    createdAt: now,\n    updatedAt: now,\n  };\n\n  if (isApiEnabled()) {\n    const result = await apiPost<{ success: boolean; registration: Registration }>({\n      action: 'createRegistration',\n      data: registration,\n    });\n    return result.registration ?? registration;\n  }\n\n  const registrations = await loadRegistrations();\n  if (!isPilotNumberAvailable(registrations, data.eventId, data.numeroPiloto)) {\n    throw new Error(`El numero de piloto ${data.numeroPiloto} ya esta registrado en este evento.`);\n  }\n\n  registrations.push(registration);\n  await saveRegistrations(registrations);\n  return registration;\n}\n\nexport async function updateRegistration(\n  id: string,\n  updates: Partial<Registration>\n): Promise<Registration> {\n  if (isApiEnabled()) {\n    const result = await apiPost<{ registration: Registration }>({\n      action: 'updateRegistration',\n      id,\n      data: updates,\n    });\n    return result.registration;\n  }\n\n  const registrations = await loadRegistrations();\n  const index = registrations.findIndex((r) => r.id === id);\n  if (index === -1) throw new Error('Inscripcion no encontrada.');\n\n  const current = registrations[index];\n  const merged = { ...current, ...updates, updatedAt: new Date().toISOString() };\n\n  if (\n    updates.numeroPiloto !== undefined &&\n    !isPilotNumberAvailable(registrations, merged.eventId, merged.numeroPiloto, id)\n  ) {\n    throw new Error(`El numero de piloto ${merged.numeroPiloto} ya esta en uso.`);\n  }\n\n  if (updates.fechaNacimiento) {\n    merged.edad = calculateAge(updates.fechaNacimiento);\n  }\n\n  if (updates.categoriaId) {\n    const firstId = updates.categoriaId.split(',')[0]?.trim();\n    const cat = firstId ? getCategoryById(firstId) : undefined;\n    merged.categoriaLabel = cat?.label ?? updates.categoriaId;\n  }\n\n  registrations[index] = merged;\n  await saveRegistrations(registrations);\n  return merged;\n}\n\nexport async function deleteRegistration(id: string): Promise<void> {\n  if (isApiEnabled()) {\n    await apiPost({ action: 'deleteRegistration', id });\n    return;\n  }\n  const registrations = await loadRegistrations();\n  await saveRegistrations(registrations.filter((r) => r.id !== id));\n}\n\nexport async function exportAllData(): Promise<AppData> {\n  const [events, registrations] = await Promise.all([loadEvents(), loadRegistrations()]);\n  return { events, registrations };\n}\n\nexport async function importData(data: AppData, mode: 'merge' | 'replace' = 'merge'): Promise<void> {\n  if (mode === 'replace') {\n    await saveEvents(data.events);\n    await saveRegistrations(data.registrations);\n    return;\n  }\n\n  const [existingEvents, existingRegs] = await Promise.all([loadEvents(), loadRegistrations()]);\n  const eventMap = new Map(existingEvents.map((e) => [e.id, e]));\n  const regMap = new Map(existingRegs.map((r) => [r.id, r]));\n\n  for (const e of data.events) eventMap.set(e.id, e);\n  for (const r of data.registrations) regMap.set(r.id, r);\n\n  await saveEvents(Array.from(eventMap.values()));\n  await saveRegistrations(Array.from(regMap.values()));\n}\n\nexport function downloadJson(data: unknown, filename: string): void {\n  const blob = new Blob([JSON.stringify(data, null, 2)], { type: 'application/json' });\n  const url = URL.createObjectURL(blob);\n  const a = document.createElement('a');\n  a.href = url;\n  a.download = filename;\n  a.click();\n  URL.revokeObjectURL(url);\n}\n\nexport async function readFileAsDataUrl(file: File): Promise<string> {\n  return new Promise((resolve, reject) => {\n    const reader = new FileReader();\n    reader.onload = () => resolve(reader.result as string);\n    reader.onerror = () => reject(new Error('No se pudo leer el archivo.'));\n    reader.readAsDataURL(file);\n  });\n}\n\nexport { isApiEnabled } from './api';","src/pages/events.ts":"import { renderNavbar, initNavbar } from '../components/navbar';\nimport { loadEvents } from '../utils/storage';\nimport { formatDate } from '../utils/age';\nimport type { Event } from '../types';\n\nfunction renderEventCard(event: Event): string {\n  return `\n    <article class=\"card group\">\n      <div class=\"flex items-start justify-between gap-4 mb-4\">\n        <div>\n          <span class=\"inline-block rounded-full bg-accent/20 px-3 py-1 text-xs font-semibold text-accent mb-2\">ACTIVO</span>\n          <h3 class=\"font-title text-2xl tracking-wide text-white group-hover:text-secondary transition-colors\">${event.name}</h3>\n        </div>\n        <div class=\"text-right shrink-0\">\n          <p class=\"font-title text-xl text-secondary\">${formatDate(event.date)}</p>\n        </div>\n      </div>\n      <p class=\"text-gray-light mb-2\">📍 ${event.location}, ${event.city}</p>\n      <p class=\"text-gray-light/80 mb-6 text-sm leading-relaxed\">${event.description}</p>\n      <a href=\"./inscripcion.html?evento=${event.id}\" class=\"btn-primary w-full sm:w-auto\">\n        Inscribirme en este evento\n      </a>\n    </article>`;\n}\n\nexport async function initEventsPage(): Promise<void> {\n  const app = document.getElementById('app');\n  if (!app) return;\n\n  app.innerHTML = `\n    ${renderNavbar('eventos')}\n    <main class=\"mx-auto max-w-7xl px-4 py-12\">\n      <div class=\"mb-10 text-center\">\n        <h1 class=\"section-title mb-4\">Eventos Activos</h1>\n        <p class=\"text-gray-light max-w-2xl mx-auto\">\n          Consulta las válidas abiertas para inscripción y regístrate directamente desde aquí.\n        </p>\n      </div>\n      <div id=\"events-list\" class=\"grid gap-6 md:grid-cols-2\">\n        <div class=\"col-span-full text-center text-gray-light py-12\">Cargando eventos...</div>\n      </div>\n    </main>\n    <footer class=\"border-t border-secondary/20 bg-dark py-8 mt-8\">\n      <div class=\"mx-auto max-w-7xl px-4 text-center text-sm text-gray-light\">\n        <p>Minicross Colombia 2026 · Triple Corona</p>\n      </div>\n    </footer>\n  `;\n\n  initNavbar();\n\n  const events = await loadEvents();\n  const activeEvents = events.filter((e) => e.active);\n  const list = document.getElementById('events-list');\n\n  if (!list) return;\n\n  if (activeEvents.length === 0) {\n    list.innerHTML = `\n      <div class=\"col-span-full card text-center py-12\">\n        <p class=\"text-gray-light text-lg mb-4\">No hay eventos activos en este momento.</p>\n        <p class=\"text-sm text-gray-light/60\">Vuelve pronto o contáctanos para más información.</p>\n      </div>`;\n    return;\n  }\n\n  list.innerHTML = activeEvents.map(renderEventCard).join('');\n}\n","src/pages/registration.ts":"import { CONFIG } from '../config';\nimport { renderNavbar, initNavbar } from '../components/navbar';\nimport {\n  createRegistration,\n  loadEvents,\n  getAvailablePilotNumbers,\n  readFileAsDataUrl,\n} from '../utils/storage';\nimport { calculateAge, formatDate } from '../utils/age';\nimport { getCategoriesForAge } from '../types';\nimport type { Event } from '../types';\nimport Swal from 'sweetalert2';\n\nlet idFileData = '';\nlet idFileName = '';\nlet idFileType = '';\nlet paymentFileData = '';\nlet paymentFileName = '';\nlet paymentFileType = '';\n\nfunction getEventIdFromUrl(): string | null {\n  return new URLSearchParams(window.location.search).get('evento');\n}\n\nfunction renderCategoryCheckboxes(age: number, selected: string[] = []): string {\n  const categories = getCategoriesForAge(age);\n  if (categories.length === 0) {\n    return '<p class=\"text-sm text-gray-light\">Sin categorias disponibles para esta edad.</p>';\n  }\n  return `<div class=\"space-y-2\" id=\"categoria-checkboxes\">\n    ${categories\n      .map(\n        (c) => `\n      <label class=\"flex items-center gap-3 rounded-lg border border-secondary/20 bg-primary/40 px-4 py-3 cursor-pointer hover:border-secondary/50\">\n        <input type=\"checkbox\" name=\"categoriaIds\" value=\"${c.id}\" class=\"accent-secondary h-4 w-4\" ${selected.includes(c.id) ? 'checked' : ''} />\n        <span class=\"text-sm font-medium\">${c.label}</span>\n      </label>`\n      )\n      .join('')}\n  </div>`;\n}\n\nfunction renderPilotOptions(numbers: number[], selected?: number): string {\n  if (numbers.length === 0) {\n    return '<option value=\"\">No hay numeros disponibles</option>';\n  }\n  return (\n    '<option value=\"\">Selecciona numero de piloto</option>' +\n    numbers\n      .map((n) => `<option value=\"${n}\" ${selected === n ? 'selected' : ''}>#${n}</option>`)\n      .join('')\n  );\n}\n\nfunction renderForm(events: Event[], selectedEventId: string | null, pilotNumbers: number[]): string {\n  const eventOptions = events\n    .filter((e) => e.active)\n    .map(\n      (e) =>\n        `<option value=\"${e.id}\" ${e.id === selectedEventId ? 'selected' : ''}>${e.name} — ${formatDate(e.date)}</option>`\n    )\n    .join('');\n\n  return `\n    <form id=\"registration-form\" class=\"space-y-6\">\n      <div>\n        <label class=\"block text-sm font-medium text-secondary mb-2\" for=\"eventId\">Evento *</label>\n        <select id=\"eventId\" name=\"eventId\" required class=\"input-field\">${eventOptions}</select>\n      </div>\n\n      <div class=\"grid gap-6 sm:grid-cols-2\">\n        <div>\n          <label class=\"block text-sm font-medium text-secondary mb-2\" for=\"nombre\">Nombre *</label>\n          <input type=\"text\" id=\"nombre\" name=\"nombre\" required class=\"input-field\" autocomplete=\"given-name\" />\n        </div>\n        <div>\n          <label class=\"block text-sm font-medium text-secondary mb-2\" for=\"apellido\">Apellido *</label>\n          <input type=\"text\" id=\"apellido\" name=\"apellido\" required class=\"input-field\" autocomplete=\"family-name\" />\n        </div>\n      </div>\n\n      <div>\n        <label class=\"block text-sm font-medium text-secondary mb-2\" for=\"identificacion\">Numero de identificacion *</label>\n        <input type=\"text\" id=\"identificacion\" name=\"identificacion\" required class=\"input-field mb-3\" placeholder=\"Ej: 1234567890\" />\n        <label class=\"block text-sm font-medium text-gray-light mb-2\" for=\"idFile\">Documento de identidad (foto o PDF, max. ${CONFIG.maxFileSizeMB} MB) *</label>\n        <input type=\"file\" id=\"idFile\" accept=\"image/*,.pdf\" required\n               class=\"w-full rounded-xl border border-dashed border-secondary/40 bg-primary/40 px-4 py-3 text-sm file:mr-4 file:rounded-lg file:border-0 file:bg-secondary file:px-4 file:py-2 file:font-semibold file:text-primary\" />\n        <p id=\"file-preview\" class=\"mt-2 text-sm text-gray-light hidden\"></p>\n      </div>\n\n      <div>\n        <label class=\"block text-sm font-medium text-secondary mb-2\" for=\"paymentFile\">Comprobante de pago (foto o PDF, max. ${CONFIG.maxFileSizeMB} MB) *</label>\n        <input type=\"file\" id=\"paymentFile\" accept=\"image/*,.pdf\" required\n               class=\"w-full rounded-xl border border-dashed border-secondary/40 bg-primary/40 px-4 py-3 text-sm file:mr-4 file:rounded-lg file:border-0 file:bg-secondary file:px-4 file:py-2 file:font-semibold file:text-primary\" />\n        <p id=\"payment-preview\" class=\"mt-2 text-sm text-gray-light hidden\"></p>\n      </div>\n\n      <div>\n        <label class=\"block text-sm font-medium text-secondary mb-2\" for=\"fechaNacimiento\">Fecha de nacimiento *</label>\n        <input type=\"date\" id=\"fechaNacimiento\" name=\"fechaNacimiento\" required class=\"input-field\" />\n        <p id=\"age-display\" class=\"mt-2 text-sm text-accent font-semibold hidden\"></p>\n      </div>\n\n      <div class=\"grid gap-6 sm:grid-cols-2\">\n        <div>\n          <label class=\"block text-sm font-medium text-secondary mb-2\" for=\"email\">Correo electronico *</label>\n          <input type=\"email\" id=\"email\" name=\"email\" required class=\"input-field\" autocomplete=\"email\" />\n        </div>\n        <div>\n          <label class=\"block text-sm font-medium text-secondary mb-2\" for=\"celular\">Celular *</label>\n          <input type=\"tel\" id=\"celular\" name=\"celular\" required class=\"input-field\" placeholder=\"300 123 4567\" autocomplete=\"tel\" />\n        </div>\n      </div>\n\n      <div class=\"grid gap-6 sm:grid-cols-2\">\n        <div>\n          <label class=\"block text-sm font-medium text-secondary mb-2\" for=\"ciudad\">Ciudad *</label>\n          <input type=\"text\" id=\"ciudad\" name=\"ciudad\" required class=\"input-field\" />\n        </div>\n        <div>\n          <label class=\"block text-sm font-medium text-secondary mb-2\" for=\"marcaMoto\">Marca moto *</label>\n          <input type=\"text\" id=\"marcaMoto\" name=\"marcaMoto\" required class=\"input-field\" placeholder=\"Ej: KTM, Yamaha, Honda...\" />\n        </div>\n      </div>\n\n      <div class=\"grid gap-6 sm:grid-cols-2\">\n        <div>\n          <label class=\"block text-sm font-medium text-secondary mb-2\" for=\"numeroPiloto\">Numero de piloto *</label>\n          <select id=\"numeroPiloto\" name=\"numeroPiloto\" required class=\"input-field\">\n            ${renderPilotOptions(pilotNumbers)}\n          </select>\n          <p id=\"pilot-status\" class=\"mt-1 text-xs text-gray-light\">Selecciona un evento para ver numeros disponibles.</p>\n        </div>\n        <div>\n          <label class=\"block text-sm font-medium text-secondary mb-2\">Categorias * (puedes elegir mas de una si aplica)</label>\n          <div id=\"categoria-container\" class=\"opacity-60 pointer-events-none\">\n            <p class=\"text-sm text-gray-light\">Primero ingresa tu fecha de nacimiento</p>\n          </div>\n        </div>\n      </div>\n\n      <button type=\"submit\" class=\"btn-primary w-full text-lg py-4\">Enviar inscripcion</button>\n    </form>`;\n}\n\nasync function refreshPilotSelect(eventId: string): Promise<void> {\n  const select = document.getElementById('numeroPiloto') as HTMLSelectElement | null;\n  const status = document.getElementById('pilot-status');\n  if (!select || !status) return;\n\n  if (!eventId) {\n    select.innerHTML = '<option value=\"\">Selecciona un evento</option>';\n    status.textContent = 'Selecciona un evento para ver numeros disponibles.';\n    return;\n  }\n\n  status.textContent = 'Cargando numeros disponibles...';\n  const numbers = await getAvailablePilotNumbers(eventId);\n  const current = Number(select.value);\n  select.innerHTML = renderPilotOptions(numbers, current || undefined);\n  status.textContent = numbers.length\n    ? `${numbers.length} numero(s) disponible(s) para este evento.`\n    : 'No hay numeros disponibles en este evento.';\n}\n\nfunction updateCategories(age: number): void {\n  const container = document.getElementById('categoria-container');\n  const ageDisplay = document.getElementById('age-display');\n  if (!container || !ageDisplay) return;\n\n  if (age < 0) {\n    ageDisplay.classList.add('hidden');\n    container.classList.add('opacity-60', 'pointer-events-none');\n    container.innerHTML = '<p class=\"text-sm text-gray-light\">Fecha invalida</p>';\n    return;\n  }\n\n  ageDisplay.textContent = `Edad calculada: ${age} anos`;\n  ageDisplay.classList.remove('hidden');\n\n  const categories = getCategoriesForAge(age);\n  container.classList.toggle('opacity-60', categories.length === 0);\n  container.classList.toggle('pointer-events-none', categories.length === 0);\n  container.innerHTML = renderCategoryCheckboxes(age);\n}\n\nfunction getSelectedCategoryIds(): string[] {\n  return Array.from(\n    document.querySelectorAll<HTMLInputElement>('input[name=\"categoriaIds\"]:checked')\n  ).map((el) => el.value);\n}\n\nasync function handleFileInput(\n  input: HTMLInputElement,\n  previewId: string,\n  onData: (data: string, name: string, type: string) => void,\n  clear: () => void\n): Promise<void> {\n  const file = input.files?.[0];\n  const preview = document.getElementById(previewId);\n  if (!file || !preview) return;\n\n  const maxBytes = CONFIG.maxFileSizeMB * 1024 * 1024;\n  if (file.size > maxBytes) {\n    preview.textContent = `Archivo demasiado grande. Maximo ${CONFIG.maxFileSizeMB} MB.`;\n    preview.classList.remove('hidden');\n    input.value = '';\n    clear();\n    return;\n  }\n\n  const data = await readFileAsDataUrl(file);\n  onData(data, file.name, file.type);\n  preview.textContent = `Archivo seleccionado: ${file.name}`;\n  preview.classList.remove('hidden');\n}\n\nexport async function initRegistrationPage(): Promise<void> {\n  const app = document.getElementById('app');\n  if (!app) return;\n\n  const events = (await loadEvents()).filter((e) => e.active);\n  const eventIdFromUrl = getEventIdFromUrl();\n  const initialEventId = eventIdFromUrl && events.some((e) => e.id === eventIdFromUrl)\n    ? eventIdFromUrl\n    : events[0]?.id ?? null;\n\n  const initialPilots = initialEventId ? await getAvailablePilotNumbers(initialEventId) : [];\n\n  app.innerHTML = `\n    ${renderNavbar('inscripcion')}\n    <main class=\"mx-auto max-w-3xl px-4 py-12\">\n      <div class=\"mb-8 text-center\">\n        <h1 class=\"section-title mb-4\">Inscripcion de Piloto</h1>\n        <p class=\"text-gray-light\">Completa el formulario para registrarte en el campeonato Minicross Colombia 2026.</p>\n      </div>\n      <div class=\"card\">\n        ${\n          events.length === 0\n            ? '<p class=\"text-center text-gray-light py-8\">No hay eventos abiertos para inscripcion.</p>'\n            : renderForm(events, initialEventId, initialPilots)\n        }\n      </div>\n    </main>\n    <footer class=\"border-t border-secondary/20 bg-dark py-8 mt-8\">\n      <div class=\"mx-auto max-w-7xl px-4 text-center text-sm text-gray-light\">\n        <p>Minicross Colombia 2026</p>\n      </div>\n    </footer>\n  `;\n\n  initNavbar();\n  if (events.length === 0) return;\n\n  const form = document.getElementById('registration-form') as HTMLFormElement | null;\n  const eventSelect = document.getElementById('eventId') as HTMLSelectElement | null;\n  const birthInput = document.getElementById('fechaNacimiento') as HTMLInputElement | null;\n  const fileInput = document.getElementById('idFile') as HTMLInputElement | null;\n  const paymentInput = document.getElementById('paymentFile') as HTMLInputElement | null;\n\n  eventSelect?.addEventListener('change', () => {\n    if (eventSelect.value) void refreshPilotSelect(eventSelect.value);\n  });\n\n  birthInput?.addEventListener('change', () => {\n    if (birthInput.value) updateCategories(calculateAge(birthInput.value));\n  });\n\n  fileInput?.addEventListener('change', () => {\n    void handleFileInput(\n      fileInput,\n      'file-preview',\n      (data, name, type) => {\n        idFileData = data;\n        idFileName = name;\n        idFileType = type;\n      },\n      () => {\n        idFileData = '';\n        idFileName = '';\n        idFileType = '';\n      }\n    );\n  });\n\n  paymentInput?.addEventListener('change', () => {\n    void handleFileInput(\n      paymentInput,\n      'payment-preview',\n      (data, name, type) => {\n        paymentFileData = data;\n        paymentFileName = name;\n        paymentFileType = type;\n      },\n      () => {\n        paymentFileData = '';\n        paymentFileName = '';\n        paymentFileType = '';\n      }\n    );\n  });\n\n  form?.addEventListener('submit', async (e) => {\n    e.preventDefault();\n\n    const fd = new FormData(form);\n    const fechaNacimiento = fd.get('fechaNacimiento') as string;\n    const edad = calculateAge(fechaNacimiento);\n    const categoriaIds = getSelectedCategoryIds();\n\n    if (edad < 0) {\n      await Swal.fire({ icon: 'error', title: 'Fecha invalida', text: 'Revisa la fecha de nacimiento.' });\n      return;\n    }\n\n    const validCategories = getCategoriesForAge(edad);\n    if (categoriaIds.length === 0 || !categoriaIds.every((id) => validCategories.some((c) => c.id === id))) {\n      await Swal.fire({\n        icon: 'error',\n        title: 'Categorias',\n        text: 'Selecciona al menos una categoria valida para tu edad.',\n      });\n      return;\n    }\n\n    if (!idFileData) {\n      await Swal.fire({ icon: 'error', title: 'Documento', text: 'Debes adjuntar el documento de identidad.' });\n      return;\n    }\n\n    if (!paymentFileData) {\n      await Swal.fire({ icon: 'error', title: 'Pago', text: 'Debes adjuntar el comprobante de pago.' });\n      return;\n    }\n\n    const numeroPiloto = Number(fd.get('numeroPiloto'));\n    if (!numeroPiloto) {\n      await Swal.fire({ icon: 'error', title: 'Numero de piloto', text: 'Selecciona un numero de piloto.' });\n      return;\n    }\n\n    Swal.fire({\n      title: 'Enviando inscripcion...',\n      allowOutsideClick: false,\n      didOpen: () => Swal.showLoading(),\n    });\n\n    try {\n      await createRegistration({\n        eventId: fd.get('eventId') as string,\n        nombre: fd.get('nombre') as string,\n        apellido: fd.get('apellido') as string,\n        identificacion: fd.get('identificacion') as string,\n        identificacionArchivo: idFileData,\n        identificacionFileName: idFileName,\n        identificacionFileType: idFileType,\n        comprobantePagoArchivo: paymentFileData,\n        comprobantePagoFileName: paymentFileName,\n        comprobantePagoFileType: paymentFileType,\n        fechaNacimiento,\n        email: fd.get('email') as string,\n        celular: fd.get('celular') as string,\n        ciudad: fd.get('ciudad') as string,\n        marcaMoto: fd.get('marcaMoto') as string,\n        numeroPiloto,\n        categoriaIds,\n      });\n\n      await Swal.fire({\n        icon: 'success',\n        title: 'Inscripcion enviada',\n        text: 'Te contactaremos pronto con los detalles del evento.',\n      });\n\n      form.reset();\n      idFileData = '';\n      idFileName = '';\n      idFileType = '';\n      paymentFileData = '';\n      paymentFileName = '';\n      paymentFileType = '';\n      document.getElementById('file-preview')?.classList.add('hidden');\n      document.getElementById('payment-preview')?.classList.add('hidden');\n      document.getElementById('age-display')?.classList.add('hidden');\n      const container = document.getElementById('categoria-container');\n      if (container) {\n        container.classList.add('opacity-60', 'pointer-events-none');\n        container.innerHTML = '<p class=\"text-sm text-gray-light\">Primero ingresa tu fecha de nacimiento</p>';\n      }\n      if (eventSelect?.value) await refreshPilotSelect(eventSelect.value);\n    } catch (err) {\n      await Swal.fire({\n        icon: 'error',\n        title: 'Error',\n        text: err instanceof Error ? err.message : 'No se pudo enviar la inscripcion.',\n      });\n    }\n  });\n}","src/pages/admin.ts":"import { CONFIG } from '../config';\nimport {\n  loadEvents,\n  loadRegistrations,\n  saveEvents,\n  updateRegistration,\n  deleteRegistration,\n  isApiEnabled,\n} from '../utils/storage';\nimport { calculateAge, formatDate, generateId } from '../utils/age';\nimport { getCategoriesForAge } from '../types';\nimport type { Event, Registration } from '../types';\n\nfunction isAuthenticated(): boolean {\n  return sessionStorage.getItem(CONFIG.storageKeys.adminSession) === 'true';\n}\n\nfunction isHttpUrl(value: string): boolean {\n  return /^https?:\\/\\//i.test(value.trim());\n}\n\nfunction renderLogin(): string {\n  return `\n    <div class=\"min-h-screen flex items-center justify-center px-4\">\n      <div class=\"card w-full max-w-md\">\n        <h1 class=\"font-title text-3xl text-center text-accent mb-6 tracking-wider\">Panel de Gestion</h1>\n        <form id=\"login-form\" class=\"space-y-4\">\n          <div>\n            <label class=\"block text-sm text-secondary mb-2\" for=\"password\">Contrasena</label>\n            <input type=\"password\" id=\"password\" required class=\"input-field\" />\n          </div>\n          <div id=\"login-error\" class=\"hidden text-orange text-sm\"></div>\n          <button type=\"submit\" class=\"btn-primary w-full\">Ingresar</button>\n        </form>\n      </div>\n    </div>`;\n}\n\nfunction renderCedulaCell(reg: Registration): string {\n  const url = reg.identificacionArchivo?.trim() ?? '';\n  if (!isHttpUrl(url)) {\n    return '<span class=\"text-gray-light text-xs\">—</span>';\n  }\n  return `<a href=\"${url}\" target=\"_blank\" rel=\"noopener noreferrer\" class=\"inline-flex items-center text-secondary hover:text-accent\" title=\"Ver documento\" aria-label=\"Ver cedula\">\n    <svg xmlns=\"http://www.w3.org/2000/svg\" class=\"h-5 w-5\" fill=\"none\" viewBox=\"0 0 24 24\" stroke=\"currentColor\" stroke-width=\"2\"><path stroke-linecap=\"round\" stroke-linejoin=\"round\" d=\"M15 12a3 3 0 11-6 0 3 3 0 016 0z\"/><path stroke-linecap=\"round\" stroke-linejoin=\"round\" d=\"M2.458 12C3.732 7.943 7.523 5 12 5c4.478 0 8.268 2.943 9.542 7-1.274 4.057-5.064 7-9.542 7-4.477 0-8.268-2.943-9.542-7z\"/></svg>\n  </a>`;\n}\n\nfunction renderRegistrationRow(reg: Registration): string {\n  const firstCategoryId = reg.categoriaId.split(',')[0]?.trim() ?? '';\n  return `\n    <tr class=\"border-b border-secondary/10 hover:bg-secondary/5\" data-id=\"${reg.id}\">\n      <td class=\"px-3 py-3 text-sm\">#${reg.numeroPiloto}</td>\n      <td class=\"px-3 py-3 text-sm\">${reg.nombre} ${reg.apellido}</td>\n      <td class=\"px-3 py-3 text-sm hidden md:table-cell\">${reg.edad} anos</td>\n      <td class=\"px-3 py-3 text-sm hidden lg:table-cell\">${reg.categoriaLabel}</td>\n      <td class=\"px-3 py-3 text-sm hidden lg:table-cell\">${reg.ciudad}</td>\n      <td class=\"px-3 py-3 text-sm hidden xl:table-cell\">${reg.celular}</td>\n      <td class=\"px-3 py-3 text-sm text-center\">${renderCedulaCell(reg)}</td>\n      <td class=\"px-3 py-3 text-sm\">\n        <button class=\"edit-reg text-secondary hover:text-accent mr-2\" data-id=\"${reg.id}\">Editar</button>\n        <button class=\"delete-reg text-orange hover:text-accent\" data-id=\"${reg.id}\">Eliminar</button>\n      </td>\n    </tr>\n    <tr class=\"hidden edit-row bg-primary/40\" data-edit-id=\"${reg.id}\">\n      <td colspan=\"8\" class=\"px-4 py-4\">\n        <form class=\"edit-form grid gap-3 sm:grid-cols-2 lg:grid-cols-3\" data-id=\"${reg.id}\">\n          <input type=\"text\" name=\"nombre\" value=\"${reg.nombre}\" placeholder=\"Nombre\" class=\"input-field text-sm\" required />\n          <input type=\"text\" name=\"apellido\" value=\"${reg.apellido}\" placeholder=\"Apellido\" class=\"input-field text-sm\" required />\n          <input type=\"date\" name=\"fechaNacimiento\" value=\"${reg.fechaNacimiento}\" class=\"input-field text-sm\" required />\n          <input type=\"email\" name=\"email\" value=\"${reg.email}\" placeholder=\"Email\" class=\"input-field text-sm\" required />\n          <input type=\"tel\" name=\"celular\" value=\"${reg.celular}\" placeholder=\"Celular\" class=\"input-field text-sm\" required />\n          <input type=\"text\" name=\"ciudad\" value=\"${reg.ciudad}\" placeholder=\"Ciudad\" class=\"input-field text-sm\" required />\n          <input type=\"text\" name=\"marcaMoto\" value=\"${reg.marcaMoto}\" placeholder=\"Marca moto\" class=\"input-field text-sm\" required />\n          <input type=\"number\" name=\"numeroPiloto\" value=\"${reg.numeroPiloto}\" min=\"4\" max=\"999\" class=\"input-field text-sm\" required />\n          <select name=\"categoriaId\" class=\"input-field text-sm\" required>\n            ${getCategoriesForAge(reg.edad)\n              .map(\n                (c) =>\n                  `<option value=\"${c.id}\" ${c.id === firstCategoryId ? 'selected' : ''}>${c.label}</option>`\n              )\n              .join('')}\n          </select>\n          <div class=\"sm:col-span-2 lg:col-span-3 flex gap-2\">\n            <button type=\"submit\" class=\"btn-secondary text-sm py-2 px-4\">Guardar</button>\n            <button type=\"button\" class=\"cancel-edit btn-outline text-sm py-2 px-4\" data-id=\"${reg.id}\">Cancelar</button>\n          </div>\n        </form>\n      </td>\n    </tr>`;\n}\n\nfunction renderAdminPanel(events: Event[], registrations: Registration[]): string {\n  const activeEvents = events.filter((e) => e.active);\n\n  const eventTabs = events\n    .map(\n      (e) =>\n        `<button class=\"event-tab px-4 py-2 rounded-lg text-sm font-medium transition-all ${\n          e.active ? 'bg-secondary/20 text-secondary' : 'bg-primary/60 text-gray-light'\n        }\" data-event-id=\"${e.id}\">${e.name}</button>`\n    )\n    .join('');\n\n  const registrationsByEvent = events\n    .map((event) => {\n      const regs = registrations.filter((r) => r.eventId === event.id);\n      return `\n        <div class=\"event-panel hidden\" data-event-panel=\"${event.id}\">\n          <div class=\"flex items-center justify-between mb-4\">\n            <h3 class=\"font-title text-2xl text-accent\">${event.name}</h3>\n            <span class=\"text-sm text-gray-light\">${regs.length} inscrito(s)</span>\n          </div>\n          ${\n            regs.length === 0\n              ? '<p class=\"text-gray-light py-6 text-center\">Sin inscripciones para este evento.</p>'\n              : `<div class=\"overflow-x-auto\">\n                  <table class=\"w-full text-left\">\n                    <thead>\n                      <tr class=\"border-b border-secondary/30 text-secondary text-sm\">\n                        <th class=\"px-3 py-2\"># Piloto</th>\n                        <th class=\"px-3 py-2\">Nombre</th>\n                        <th class=\"px-3 py-2 hidden md:table-cell\">Edad</th>\n                        <th class=\"px-3 py-2 hidden lg:table-cell\">Categoria</th>\n                        <th class=\"px-3 py-2 hidden lg:table-cell\">Ciudad</th>\n                        <th class=\"px-3 py-2 hidden xl:table-cell\">Celular</th>\n                        <th class=\"px-3 py-2 text-center\">Cedula</th>\n                        <th class=\"px-3 py-2\">Acciones</th>\n                      </tr>\n                    </thead>\n                    <tbody>${regs.map((r) => renderRegistrationRow(r)).join('')}</tbody>\n                  </table>\n                </div>`\n          }\n        </div>`;\n    })\n    .join('');\n\n  return `\n    <div class=\"min-h-screen\">\n      <header class=\"border-b border-secondary/20 bg-primary/95 px-4 py-4\">\n        <div class=\"mx-auto max-w-7xl flex flex-wrap items-center justify-between gap-4\">\n          <div>\n            <h1 class=\"font-title text-3xl text-accent tracking-wider\">Panel Minicross 2026</h1>\n            <p class=\"text-sm text-gray-light\">Gestion de inscripciones y eventos</p>\n          </div>\n          <button id=\"logout-btn\" class=\"btn-outline text-sm py-2 px-4\">Cerrar sesion</button>\n        </div>\n      </header>\n\n      <main class=\"mx-auto max-w-7xl px-4 py-8 space-y-10\">\n        <section class=\"card\">\n          <h2 class=\"font-title text-2xl text-secondary mb-4\">Datos del campeonato</h2>\n          ${\n            isApiEnabled()\n              ? `<p class=\"text-secondary text-sm mb-4 font-semibold\">\n                  Conectado a Google Sheets en tiempo real. Las inscripciones y cambios se guardan automaticamente.\n                </p>`\n              : `<p class=\"text-gray-light text-sm mb-4\">\n                  Modo local activo. Configura Google Sheets (ver docs/SETUP-GOOGLE-SHEETS.md) y la URL en src/config.ts.\n                </p>`\n          }\n          <a href=\"${CONFIG.spreadsheetUrl}\" target=\"_blank\" rel=\"noopener noreferrer\" class=\"btn-primary inline-block\">\n            Abrir Google Sheet\n          </a>\n        </section>\n\n        <section class=\"card\">\n          <div class=\"flex items-center justify-between mb-4\">\n            <h2 class=\"font-title text-2xl text-secondary\">Eventos (${activeEvents.length} activos)</h2>\n            <button id=\"add-event-btn\" class=\"btn-secondary text-sm py-2 px-4\">+ Nuevo evento</button>\n          </div>\n          <div id=\"events-admin\" class=\"space-y-3\">\n            ${events\n              .map(\n                (e) => `\n              <div class=\"flex flex-wrap items-center gap-3 rounded-lg border border-secondary/20 bg-primary/40 p-4\" data-event-admin=\"${e.id}\">\n                <div class=\"flex-1 min-w-[200px]\">\n                  <p class=\"font-semibold\">${e.name}</p>\n                  <p class=\"text-sm text-gray-light\">${formatDate(e.date)} · ${e.city}</p>\n                </div>\n                <label class=\"flex items-center gap-2 text-sm\">\n                  <input type=\"checkbox\" class=\"event-active-toggle accent-secondary\" data-id=\"${e.id}\" ${e.active ? 'checked' : ''} />\n                  Activo\n                </label>\n                <button class=\"edit-event-btn text-secondary text-sm hover:text-accent\" data-id=\"${e.id}\">Editar</button>\n                <button class=\"delete-event-btn text-orange text-sm hover:text-accent\" data-id=\"${e.id}\">Eliminar</button>\n              </div>`\n              )\n              .join('')}\n          </div>\n          <form id=\"event-form\" class=\"hidden mt-4 space-y-3 border-t border-secondary/20 pt-4\">\n            <input type=\"hidden\" id=\"event-form-id\" />\n            <div class=\"grid gap-3 sm:grid-cols-2\">\n              <input type=\"text\" id=\"event-name\" placeholder=\"Nombre del evento\" class=\"input-field\" required />\n              <input type=\"date\" id=\"event-date\" class=\"input-field\" required />\n              <input type=\"text\" id=\"event-location\" placeholder=\"Ubicacion / Pista\" class=\"input-field\" required />\n              <input type=\"text\" id=\"event-city\" placeholder=\"Ciudad\" class=\"input-field\" required />\n            </div>\n            <textarea id=\"event-description\" placeholder=\"Descripcion\" class=\"input-field\" rows=\"2\" required></textarea>\n            <div class=\"flex gap-2\">\n              <button type=\"submit\" class=\"btn-primary text-sm py-2 px-4\">Guardar evento</button>\n              <button type=\"button\" id=\"cancel-event-form\" class=\"btn-outline text-sm py-2 px-4\">Cancelar</button>\n            </div>\n          </form>\n        </section>\n\n        <section class=\"card\">\n          <h2 class=\"font-title text-2xl text-secondary mb-4\">Inscripciones por evento</h2>\n          <div class=\"flex flex-wrap gap-2 mb-6\">${eventTabs}</div>\n          <div id=\"registrations-panels\">${registrationsByEvent}</div>\n        </section>\n      </main>\n    </div>`;\n}\n\nasync function refreshAdmin(): Promise<void> {\n  const app = document.getElementById('app');\n  if (!app) return;\n  const [events, registrations] = await Promise.all([loadEvents(), loadRegistrations()]);\n  app.innerHTML = renderAdminPanel(events, registrations);\n  bindAdminEvents(events);\n}\n\nfunction bindAdminEvents(events: Event[]): void {\n  document.getElementById('logout-btn')?.addEventListener('click', () => {\n    sessionStorage.removeItem(CONFIG.storageKeys.adminSession);\n    initAdminPage();\n  });\n\n  const panels = document.querySelectorAll('.event-panel');\n  const tabs = document.querySelectorAll('.event-tab');\n  if (panels.length > 0) {\n    (panels[0] as HTMLElement).classList.remove('hidden');\n  }\n  tabs.forEach((tab) => {\n    tab.addEventListener('click', () => {\n      const eventId = tab.getAttribute('data-event-id');\n      tabs.forEach((t) => t.classList.remove('ring-2', 'ring-secondary'));\n      tab.classList.add('ring-2', 'ring-secondary');\n      panels.forEach((p) => {\n        p.classList.toggle('hidden', p.getAttribute('data-event-panel') !== eventId);\n      });\n    });\n  });\n  tabs[0]?.classList.add('ring-2', 'ring-secondary');\n\n  document.querySelectorAll('.event-active-toggle').forEach((toggle) => {\n    toggle.addEventListener('change', async (e) => {\n      const id = (e.target as HTMLInputElement).getAttribute('data-id')!;\n      const updated = events.map((ev) =>\n        ev.id === id ? { ...ev, active: (e.target as HTMLInputElement).checked } : ev\n      );\n      await saveEvents(updated);\n    });\n  });\n\n  const eventForm = document.getElementById('event-form') as HTMLFormElement;\n  document.getElementById('add-event-btn')?.addEventListener('click', () => {\n    eventForm.classList.remove('hidden');\n    (document.getElementById('event-form-id') as HTMLInputElement).value = '';\n    eventForm.reset();\n  });\n  document.getElementById('cancel-event-form')?.addEventListener('click', () => {\n    eventForm.classList.add('hidden');\n  });\n\n  document.querySelectorAll('.edit-event-btn').forEach((btn) => {\n    btn.addEventListener('click', () => {\n      const id = btn.getAttribute('data-id')!;\n      const event = events.find((e) => e.id === id);\n      if (!event) return;\n      eventForm.classList.remove('hidden');\n      (document.getElementById('event-form-id') as HTMLInputElement).value = event.id;\n      (document.getElementById('event-name') as HTMLInputElement).value = event.name;\n      (document.getElementById('event-date') as HTMLInputElement).value = event.date;\n      (document.getElementById('event-location') as HTMLInputElement).value = event.location;\n      (document.getElementById('event-city') as HTMLInputElement).value = event.city;\n      (document.getElementById('event-description') as HTMLTextAreaElement).value = event.description;\n    });\n  });\n\n  document.querySelectorAll('.delete-event-btn').forEach((btn) => {\n    btn.addEventListener('click', async () => {\n      const id = btn.getAttribute('data-id')!;\n      if (!confirm('Eliminar este evento? Las inscripciones asociadas permaneceran.')) return;\n      await saveEvents(events.filter((e) => e.id !== id));\n      await refreshAdmin();\n    });\n  });\n\n  eventForm?.addEventListener('submit', async (e) => {\n    e.preventDefault();\n    const formId = (document.getElementById('event-form-id') as HTMLInputElement).value;\n    const newEvent: Event = {\n      id: formId || generateId(),\n      name: (document.getElementById('event-name') as HTMLInputElement).value,\n      date: (document.getElementById('event-date') as HTMLInputElement).value,\n      location: (document.getElementById('event-location') as HTMLInputElement).value,\n      city: (document.getElementById('event-city') as HTMLInputElement).value,\n      description: (document.getElementById('event-description') as HTMLTextAreaElement).value,\n      active: true,\n    };\n\n    const updated = formId\n      ? events.map((ev) => (ev.id === formId ? { ...ev, ...newEvent, id: formId } : ev))\n      : [...events, newEvent];\n\n    await saveEvents(updated);\n    await refreshAdmin();\n  });\n\n  document.querySelectorAll('.edit-reg').forEach((btn) => {\n    btn.addEventListener('click', () => {\n      const id = btn.getAttribute('data-id')!;\n      document.querySelector(`[data-edit-id=\"${id}\"]`)?.classList.remove('hidden');\n    });\n  });\n\n  document.querySelectorAll('.cancel-edit').forEach((btn) => {\n    btn.addEventListener('click', () => {\n      const id = btn.getAttribute('data-id')!;\n      document.querySelector(`[data-edit-id=\"${id}\"]`)?.classList.add('hidden');\n    });\n  });\n\n  document.querySelectorAll('.delete-reg').forEach((btn) => {\n    btn.addEventListener('click', async () => {\n      const id = btn.getAttribute('data-id')!;\n      if (!confirm('Eliminar esta inscripcion?')) return;\n      await deleteRegistration(id);\n      await refreshAdmin();\n    });\n  });\n\n  document.querySelectorAll('.edit-form').forEach((form) => {\n    form.addEventListener('submit', async (e) => {\n      e.preventDefault();\n      const id = form.getAttribute('data-id')!;\n      const fd = new FormData(form as HTMLFormElement);\n      const catId = fd.get('categoriaId') as string;\n      const cat = getCategoriesForAge(calculateAge(fd.get('fechaNacimiento') as string)).find((c) => c.id === catId);\n      try {\n        await updateRegistration(id, {\n          nombre: fd.get('nombre') as string,\n          apellido: fd.get('apellido') as string,\n          fechaNacimiento: fd.get('fechaNacimiento') as string,\n          email: fd.get('email') as string,\n          celular: fd.get('celular') as string,\n          ciudad: fd.get('ciudad') as string,\n          marcaMoto: fd.get('marcaMoto') as string,\n          numeroPiloto: Number(fd.get('numeroPiloto')),\n          categoriaId: catId,\n          categoriaLabel: cat?.label ?? catId,\n        });\n        await refreshAdmin();\n      } catch (err) {\n        alert(err instanceof Error ? err.message : 'Error al guardar.');\n      }\n    });\n  });\n}\n\nexport async function initAdminPage(): Promise<void> {\n  const app = document.getElementById('app');\n  if (!app) return;\n\n  if (!isAuthenticated()) {\n    app.innerHTML = renderLogin();\n    document.getElementById('login-form')?.addEventListener('submit', (e) => {\n      e.preventDefault();\n      const password = (document.getElementById('password') as HTMLInputElement).value;\n      const errorEl = document.getElementById('login-error');\n      if (password === CONFIG.adminPassword) {\n        sessionStorage.setItem(CONFIG.storageKeys.adminSession, 'true');\n        initAdminPage();\n      } else if (errorEl) {\n        errorEl.textContent = 'Contrasena incorrecta.';\n        errorEl.classList.remove('hidden');\n      }\n    });\n    return;\n  }\n\n  await refreshAdmin();\n}","src/pages/home.ts":"import { renderNavbar, initNavbar } from '../components/navbar';\n\nexport function initHomePage(): void {\n  const app = document.getElementById('app');\n  if (!app) return;\n\n  app.innerHTML = `\n    ${renderNavbar('home')}\n\n    <section class=\"relative overflow-hidden dirt-texture\">\n      <div class=\"mx-auto max-w-7xl px-4 py-16 md:py-24\">\n        <div class=\"grid items-center gap-12 md:grid-cols-2\">\n          <div class=\"animate-fade-in-up\">\n            <span class=\"shield-badge mb-4\">Triple Corona · 3 Mangas</span>\n            <h1 class=\"font-title text-5xl leading-tight tracking-wider md:text-7xl\">\n              CAMPEONATO<br/>\n              <span class=\"text-accent\">MINICROSS</span><br/>\n              COLOMBIA 2026\n            </h1>\n            <p class=\"mt-6 text-lg text-gray-light leading-relaxed\">\n              Velocidad, energía y competencia off-road. El campeonato que reúne a los mejores\n              pilotos juveniles de motocross en categorías desde 50 cc hasta 125 cc Junior.\n            </p>\n            <div class=\"mt-8 flex flex-wrap gap-4\">\n              <a href=\"./inscripcion.html\" class=\"btn-primary\">Inscríbete ahora</a>\n              <a href=\"./eventos.html\" class=\"btn-outline\">Ver eventos</a>\n            </div>\n          </div>\n          <div class=\"flex justify-center animate-fade-in-up\">\n            <img src=\"./logo-minicross.jpg\" alt=\"Logo Campeonato Minicross Colombia 2026\"\n                 class=\"max-w-sm rounded-2xl shadow-glow-yellow md:max-w-md\" />\n          </div>\n        </div>\n      </div>\n    </section>\n\n    <section class=\"border-y border-secondary/20 bg-dark/50 py-16\">\n      <div class=\"mx-auto max-w-7xl px-4\">\n        <h2 class=\"section-title text-center mb-12\">¿Qué es el Minicross?</h2>\n        <div class=\"grid gap-8 md:grid-cols-3\">\n          <div class=\"card text-center\">\n            <div class=\"mx-auto mb-4 flex h-16 w-16 items-center justify-center rounded-full bg-secondary/20 text-3xl\">🏍️</div>\n            <h3 class=\"font-title text-2xl tracking-wide text-accent mb-3\">Off-Road Extremo</h3>\n            <p class=\"text-gray-light\">Motocross en su forma más pura: tierra, saltos y adrenalina en pistas diseñadas para los futuros campeones.</p>\n          </div>\n          <div class=\"card text-center\">\n            <div class=\"mx-auto mb-4 flex h-16 w-16 items-center justify-center rounded-full bg-secondary/20 text-3xl\">🏆</div>\n            <h3 class=\"font-title text-2xl tracking-wide text-accent mb-3\">Triple Corona</h3>\n            <p class=\"text-gray-light\">Tres mangas decisivas en cada válida. Acumula puntos, demuestra tu talento y compite por el título nacional.</p>\n          </div>\n          <div class=\"card text-center\">\n            <div class=\"mx-auto mb-4 flex h-16 w-16 items-center justify-center rounded-full bg-secondary/20 text-3xl\">⚡</div>\n            <h3 class=\"font-title text-2xl tracking-wide text-accent mb-3\">Categorías por Edad</h3>\n            <p class=\"text-gray-light\">Desde 50 cc para los más pequeños hasta 125 cc Junior. Cada piloto compite en la categoría acorde a su edad.</p>\n          </div>\n        </div>\n      </div>\n    </section>\n\n    <section class=\"py-16 dirt-texture\">\n      <div class=\"mx-auto max-w-7xl px-4\">\n        <h2 class=\"section-title text-center mb-4\">Categorías 2026</h2>\n        <p class=\"text-center text-gray-light mb-10 max-w-2xl mx-auto\">Compite en la categoría que corresponda a tu edad al momento del evento.</p>\n        <div class=\"grid gap-4 sm:grid-cols-2 lg:grid-cols-3 xl:grid-cols-4\">\n          ${[\n            ['50cc A', '4 – 6 años'],\n            ['50cc B', '6 – 8 años'],\n            ['65cc A', '7 – 9 años'],\n            ['65cc B', '8 – 10 años'],\n            ['85cc A', '9 – 11 años'],\n            ['85cc B', '11 – 13 años'],\n            ['125cc Junior', '12 – 17 años'],\n          ]\n            .map(\n              ([cc, age]) => `\n            <div class=\"card flex items-center gap-4\">\n              <span class=\"font-title text-3xl text-secondary\">${cc}</span>\n              <span class=\"text-gray-light font-medium\">${age}</span>\n            </div>`\n            )\n            .join('')}\n        </div>\n      </div>\n    </section>\n\n    <section class=\"border-t border-secondary/20 bg-blue-medium/30 py-16\">\n      <div class=\"mx-auto max-w-4xl px-4 text-center\">\n        <h2 class=\"section-title mb-4\">¿Listo para la acción?</h2>\n        <p class=\"text-gray-light mb-8 text-lg\">Inscríbete en la próxima válida y forma parte del Campeonato Minicross Colombia 2026.</p>\n        <a href=\"./inscripcion.html\" class=\"btn-primary text-lg px-10 py-4\">Registrarme como piloto</a>\n      </div>\n    </section>\n\n    <footer class=\"border-t border-secondary/20 bg-dark py-8\">\n      <div class=\"mx-auto max-w-7xl px-4 text-center text-sm text-gray-light\">\n        <p class=\"font-title text-xl text-accent tracking-wider mb-2\">MINICROSS COLOMBIA 2026</p>\n        <p>Campeonato Nacional de Motocross Juvenil · Triple Corona</p>\n      </div>\n    </footer>\n  `;\n\n  initNavbar();\n}\n","docs/google-apps-script.gs":"/**\n * Minicross Colombia 2026 - Google Apps Script Backend\n *\n * SETUP: ver docs/SETUP-GOOGLE-SHEETS.md\n *\n * Configura SPREADSHEET_ID y DRIVE_FOLDER_ID abajo.\n * Despliega como Web App: Ejecutar como \"Yo\", Acceso \"Cualquier persona\".\n */\n\nconst SPREADSHEET_ID = '1g5crmfmbcxyvmLMXxYECxO90gFYiXf7P5JaSze7pmbI';\nconst DRIVE_FOLDER_ID = '1oImoS0x__kgBBXaL9HAg3Qf-4Zj0Xz0l';\n\nconst EVENT_HEADERS = ['id', 'name', 'date', 'location', 'city', 'description', 'active'];\nconst REG_HEADERS = [\n  'id', 'eventId', 'nombre', 'apellido', 'identificacion',\n  'identificacionArchivo', 'identificacionFileName', 'identificacionFileType',\n  'comprobantePagoArchivo', 'comprobantePagoFileName', 'comprobantePagoFileType',\n  'fechaNacimiento', 'edad', 'email', 'celular', 'ciudad', 'marcaMoto',\n  'numeroPiloto', 'categoriaId', 'categoriaLabel', 'createdAt', 'updatedAt',\n];\n\n// ─── HTTP handlers ───────────────────────────────────────────────────────────\n\nfunction doGet(e) {\n  e = e || { parameter: {} };\n  const action = (e.parameter.action || 'all').toString();\n  const ss = SpreadsheetApp.openById(SPREADSHEET_ID);\n\n  \n  if (action === 'availablePilots') {\n    const eventId = e.parameter.eventId;\n    return jsonResponse({ numbers: getAvailablePilotNumbers_(ss, eventId) });\n  }\n\n  if (action === 'checkPilot') {\n    const eventId = e.parameter.eventId;\n    const numero = Number(e.parameter.numero);\n    const excludeId = e.parameter.excludeId || null;\n    const available = isPilotNumberAvailable_(ss, eventId, numero, excludeId);\n    return jsonResponse({ available: available });\n  }\n\n  if (action === 'events') {\n    return jsonResponse({ events: getEvents_(ss) });\n  }\n\n  if (action === 'registrations') {\n    return jsonResponse({ registrations: getRegistrations_(ss) });\n  }\n\n  return jsonResponse({\n    events: getEvents_(ss),\n    registrations: getRegistrations_(ss),\n  });\n}\n\nfunction doPost(e) {\n  if (!e || !e.postData || !e.postData.contents) {\n    return jsonResponse({\n      success: false,\n      error: 'doPost solo funciona via HTTP desde la web. Para configurar, ejecuta setupSheets.',\n    });\n  }\n  const body = JSON.parse(e.postData.contents);\n  const ss = SpreadsheetApp.openById(SPREADSHEET_ID);\n\n  switch (body.action) {\n    case 'createRegistration':\n      return jsonResponse(createRegistration_(ss, body.data));\n    case 'updateRegistration':\n      return jsonResponse(updateRegistration_(ss, body.id, body.data));\n    case 'deleteRegistration':\n      return jsonResponse(deleteRegistration_(ss, body.id));\n    case 'saveEvents':\n      writeEvents_(ss, body.events);\n      return jsonResponse({ success: true });\n    case 'saveRegistrations':\n      writeRegistrations_(ss, body.registrations);\n      return jsonResponse({ success: true });\n    default:\n      return jsonResponse({ success: false, error: 'Accion desconocida' });\n  }\n}\n\n// ─── Registrations CRUD ──────────────────────────────────────────────────────\n\nfunction createRegistration_(ss, data) {\n  if (!isPilotNumberAvailable_(ss, data.eventId, Number(data.numeroPiloto))) {\n    return {\n      success: false,\n      error: 'El numero de piloto ' + data.numeroPiloto + ' ya esta registrado en este evento.',\n    };\n  }\n\n  if (data.identificacionArchivo && data.identificacionArchivo.indexOf('data:') === 0) {\n    data.identificacionArchivo = saveFileToDrive_(data);\n  }\n\n  const sheet = getOrCreateSheet_(ss, 'Registrations', REG_HEADERS);\n  appendRow_(sheet, REG_HEADERS, data);\n  return { success: true, registration: data };\n}\n\nfunction updateRegistration_(ss, id, updates) {\n  const sheet = ss.getSheetByName('Registrations');\n  if (!sheet) return { success: false, error: 'Hoja Registrations no encontrada' };\n\n  const rows = sheetToObjects_(sheet);\n  const index = rows.findIndex(function (r) { return String(r.id) === String(id); });\n  if (index === -1) return { success: false, error: 'Inscripcion no encontrada' };\n\n  const merged = {};\n  REG_HEADERS.forEach(function (h) {\n    merged[h] = updates[h] !== undefined ? updates[h] : rows[index][h];\n  });\n  merged.id = id;\n  merged.updatedAt = new Date().toISOString();\n\n  if (\n    updates.numeroPiloto !== undefined &&\n    !isPilotNumberAvailable_(ss, merged.eventId, Number(merged.numeroPiloto), id)\n  ) {\n    return { success: false, error: 'El numero de piloto ' + merged.numeroPiloto + ' ya esta en uso.' };\n  }\n\n  const rowNum = index + 2;\n  REG_HEADERS.forEach(function (h, i) {\n    sheet.getRange(rowNum, i + 1).setValue(merged[h] !== undefined ? merged[h] : '');\n  });\n\n  return { success: true, registration: merged };\n}\n\nfunction deleteRegistration_(ss, id) {\n  const sheet = ss.getSheetByName('Registrations');\n  if (!sheet) return { success: false, error: 'Hoja no encontrada' };\n\n  const rows = sheetToObjects_(sheet);\n  const index = rows.findIndex(function (r) { return String(r.id) === String(id); });\n  if (index === -1) return { success: false, error: 'Inscripcion no encontrada' };\n\n  sheet.deleteRow(index + 2);\n  return { success: true };\n}\n\n// ─── Pilot number check ──────────────────────────────────────────────────────\n\nfunction isPilotNumberAvailable_(ss, eventId, numero, excludeId) {\n  const regs = getRegistrations_(ss);\n  for (var i = 0; i < regs.length; i++) {\n    var r = regs[i];\n    if (\n      String(r.eventId) === String(eventId) &&\n      Number(r.numeroPiloto) === Number(numero) &&\n      (!excludeId || String(r.id) !== String(excludeId))\n    ) {\n      return false;\n    }\n  }\n  return true;\n}\n\n// ─── Drive: guardar documento de identidad ───────────────────────────────────\n\nfunction saveFileToDrive_(data) {\n  try {\n    var folder = DriveApp.getFolderById(DRIVE_FOLDER_ID);\n    var parts = data.identificacionArchivo.split(',');\n    var base64 = parts.length > 1 ? parts[1] : parts[0];\n    var blob = Utilities.newBlob(\n      Utilities.base64Decode(base64),\n      data.identificacionFileType || 'application/octet-stream',\n      data.identificacionFileName || 'documento'\n    );\n    var file = folder.createFile(blob);\n    file.setSharing(DriveApp.Access.ANYONE_WITH_LINK, DriveApp.Permission.VIEW);\n    return file.getUrl();\n  } catch (err) {\n    return '[error al subir: ' + err.message + ']';\n  }\n}\n\n// ─── Events ──────────────────────────────────────────────────────────────────\n\n\nfunction parseSheetDate_(value) {\n  if (value == null || value === '') return '';\n  if (typeof value === 'number' && value > 1000) {\n    var utc = new Date((value - 25569) * 86400 * 1000);\n    if (!isNaN(utc.getTime())) return utc.toISOString().slice(0, 10);\n  }\n  var str = String(value).trim();\n  if (/^\\d{4}-\\d{2}-\\d{2}/.test(str)) return str.slice(0, 10);\n  var d = new Date(str.indexOf('T') >= 0 ? str : str + 'T12:00:00');\n  if (!isNaN(d.getTime())) return d.toISOString().slice(0, 10);\n  return str;\n}\n\nfunction getAvailablePilotNumbers_(ss, eventId) {\n  var regs = getRegistrations_(ss);\n  var taken = {};\n  for (var i = 0; i < regs.length; i++) {\n    if (String(regs[i].eventId) === String(eventId)) {\n      taken[Number(regs[i].numeroPiloto)] = true;\n    }\n  }\n  var numbers = [];\n  for (var n = 4; n <= 999; n++) {\n    if (!taken[n]) numbers.push(n);\n  }\n  return numbers;\n}\n\nfunction saveComprobanteToDrive_(data) {\n  try {\n    var folder = DriveApp.getFolderById(DRIVE_FOLDER_ID);\n    var parts = data.comprobantePagoArchivo.split(',');\n    var base64 = parts.length > 1 ? parts[1] : parts[0];\n    var blob = Utilities.newBlob(\n      Utilities.base64Decode(base64),\n      data.comprobantePagoFileType || 'application/octet-stream',\n      data.comprobantePagoFileName || 'comprobante-pago'\n    );\n    var file = folder.createFile(blob);\n    file.setSharing(DriveApp.Access.ANYONE_WITH_LINK, DriveApp.Permission.VIEW);\n    return file.getUrl();\n  } catch (err) {\n    return '[error al subir comprobante: ' + err.message + ']';\n  }\n}\n\nfunction getEvents_(ss) {\n  var sheet = ss.getSheetByName('Events');\n  if (!sheet || sheet.getLastRow() < 2) return [];\n  var events = sheetToObjects_(sheet);\n  return events.map(function (evt) {\n    evt.date = parseSheetDate_(evt.date);\n    return evt;\n  });\n}\n\nfunction getRegistrations_(ss) {\n  var sheet = ss.getSheetByName('Registrations');\n  if (!sheet || sheet.getLastRow() < 2) return [];\n  var events = sheetToObjects_(sheet);\n  return events.map(function (evt) {\n    evt.date = parseSheetDate_(evt.date);\n    return evt;\n  });\n}\n\nfunction writeEvents_(ss, events) {\n  var sheet = getOrCreateSheet_(ss, 'Events', EVENT_HEADERS);\n  writeObjects_(sheet, EVENT_HEADERS, events);\n}\n\nfunction writeRegistrations_(ss, registrations) {\n  var sheet = getOrCreateSheet_(ss, 'Registrations', REG_HEADERS);\n  writeObjects_(sheet, REG_HEADERS, registrations);\n}\n\n// ─── Sheet helpers ───────────────────────────────────────────────────────────\n\nfunction getOrCreateSheet_(ss, name, headers) {\n  var sheet = ss.getSheetByName(name);\n  if (!sheet) {\n    sheet = ss.insertSheet(name);\n    sheet.appendRow(headers);\n    sheet.getRange(1, 1, 1, headers.length).setFontWeight('bold');\n    sheet.setFrozenRows(1);\n  }\n  return sheet;\n}\n\nfunction sheetToObjects_(sheet) {\n  var data = sheet.getDataRange().getValues();\n  if (data.length < 2) return [];\n  var headers = data[0];\n  var result = [];\n  for (var i = 1; i < data.length; i++) {\n    var obj = {};\n    for (var j = 0; j < headers.length; j++) {\n      obj[headers[j]] = data[i][j];\n    }\n    result.push(obj);\n  }\n  return result;\n}\n\nfunction appendRow_(sheet, headers, obj) {\n  sheet.appendRow(headers.map(function (h) { return obj[h] !== undefined ? obj[h] : ''; }));\n}\n\nfunction writeObjects_(sheet, headers, objects) {\n  sheet.clear();\n  sheet.appendRow(headers);\n  sheet.getRange(1, 1, 1, headers.length).setFontWeight('bold');\n  sheet.setFrozenRows(1);\n  objects.forEach(function (obj) {\n    appendRow_(sheet, headers, obj);\n  });\n}\n\nfunction jsonResponse(data) {\n  return ContentService\n    .createTextOutput(JSON.stringify(data))\n    .setMimeType(ContentService.MimeType.JSON);\n}\n\n// ─── Utilidad: crear hojas iniciales (ejecutar una vez manualmente) ──────────\n\nfunction setupSheets() {\n  var ss = SpreadsheetApp.openById(SPREADSHEET_ID);\n  getOrCreateSheet_(ss, 'Events', EVENT_HEADERS);\n  getOrCreateSheet_(ss, 'Registrations', REG_HEADERS);\n\n  var eventsSheet = ss.getSheetByName('Events');\n  if (eventsSheet.getLastRow() === 1) {\n    writeEvents_(ss, [\n      {\n        id: 'evt-001',\n        name: 'Valida 1 - Bogota',\n        date: '2026-03-15',\n        location: 'Pista Off-Road El Dorado',\n        city: 'Bogota',\n        description: 'Primera valida del campeonato. Triple Corona: 3 mangas.',\n        active: true,\n      },\n      {\n        id: 'evt-002',\n        name: 'Valida 2 - Medellin',\n        date: '2026-05-20',\n        location: 'Autodromo del Oriente',\n        city: 'Medellin',\n        description: 'Segunda valida del campeonato.',\n        active: true,\n      },\n    ]);\n  }\n  Logger.log('Hojas creadas correctamente.');\n}\n\n/** Ejecuta ESTA funcion desde el editor (no doGet). Crea las hojas y eventos de ejemplo. */\nfunction testConnection() {\n  var ss = SpreadsheetApp.openById(SPREADSHEET_ID);\n  var folder = DriveApp.getFolderById(DRIVE_FOLDER_ID);\n  setupSheets();\n  Logger.log('Sheet: ' + ss.getName());\n  Logger.log('Carpeta Drive: ' + folder.getName());\n  Logger.log('Eventos: ' + getEvents_(ss).length);\n  Logger.log('Todo OK. Ahora despliega como Web App.');\n}\n"};

for (const [rel, content] of Object.entries(files)) {
  const full = path.join(root, rel);
  fs.mkdirSync(path.dirname(full), { recursive: true });
  fs.writeFileSync(full, content, 'utf8');
  console.log('Wrote', rel);
}
console.log('Done:', Object.keys(files).length, 'files');
